/* ─────────────────────────────────────────────
   FIBONACCI IMPLEMENTATIONS
───────────────────────────────────────────── */

// 🐛 BUGGY — two deliberate bugs
function fibBuggy(n) {
    if (n === 0) return 0;
    if (n === 1) return 0;           // BUG 1: should be 1
    return fibBuggy(n - 1) + fibBuggy(n - 3 < 0 ? 0 : n - 3); // BUG 2: n-3 not n-2
}

// ✅ FIXED — correct implementation
function fibFixed(n) {
    if (n === 0) return 0;
    if (n === 1) return 1;           // FIXED
    return fibFixed(n - 1) + fibFixed(n - 2); // FIXED
}

/* ─────────────────────────────────────────────
   BUILD SEQUENCE COMPARISON TABLE
───────────────────────────────────────────── */
const SCALE = 18;   // pixels per Fibonacci unit
const N     = 10;   // number of arcs

(function buildTable() {
    const tbody = document.getElementById('seqTableBody');
    for (let i = 0; i < N; i++) {
        const bv = fibBuggy(i);
        const fv = fibFixed(i);
        const tr = document.createElement('tr');
        tr.className = (bv !== fv) ? 'bad' : 'good';
        tr.innerHTML = `
            <td class="idx">${i}</td>
            <td>${bv}</td>
            <td>${fv}</td>
            <td>${(fv * SCALE).toFixed(0)} px</td>`;
        tbody.appendChild(tr);
    }
})();

/* ─────────────────────────────────────────────
   CANVAS DRAWING ENGINE
───────────────────────────────────────────── */

// Pre-compute Fibonacci numbers for drawing
const fibSeq = Array.from({ length: N }, (_, i) => fibFixed(i));

/*
  Classic Fibonacci spiral construction:
  Each square has side = fib(n) * SCALE.
  Squares are placed in sequence: right, up, left, down (rotating CCW).
  Each arc sweeps 90° (π/2) inside its square.

  Pivot corners and sweep directions for each rotation step:
    step 0 (right) : pivot = bottom-left  of square, sweep 0   → π/2  (upward arc)
    step 1 (up)    : pivot = bottom-right of square, sweep π/2 → π
    step 2 (left)  : pivot = top-right    of square, sweep π   → 3π/2
    step 3 (down)  : pivot = top-left     of square, sweep 3π/2→ 2π
*/

// Returns an array of arc descriptors for N arcs
function buildArcs(fibArray, scale) {
    const arcs = [];

    // Starting position — centre-ish of the canvas
    // We track the "cursor" (top-left of the current square block)
    let cx = 210, cy = 210;   // canvas centre
    let blockW = 0, blockH = 0;

    // We'll accumulate the bounding box offset as we place squares
    // Direction cycle: 0=right, 1=up, 2=left, 3=down
    let dir = 0;

    // Current origin of the growing rectangle (top-left corner)
    let ox = cx, oy = cy;

    for (let i = 0; i < fibArray.length; i++) {
        const r = fibArray[i] * scale;
        const side = r; // square side = radius of arc

        let pivotX, pivotY, startAngle;

        switch (dir % 4) {
            case 0: // place square to the RIGHT of current block
                pivotX   = ox + blockW;
                pivotY   = oy + blockH;
                startAngle = Math.PI;          // arc goes from left → up  (CCW: π → π/2)
                // After placing, new block grows right
                ox = ox;                       // top-left unchanged
                blockW += side;
                break;
            case 1: // place square ABOVE current block
                pivotX   = ox;
                pivotY   = oy;
                startAngle = Math.PI / 2;      // arc goes from bottom → right
                oy -= side;
                blockH += side;
                break;
            case 2: // place square to the LEFT
                pivotX   = ox;
                pivotY   = oy;
                startAngle = 0;                // arc goes from right → down
                ox -= side;
                blockW += side;
                break;
            case 3: // place square BELOW
                pivotX   = ox + blockW;
                pivotY   = oy + blockH;
                startAngle = -Math.PI / 2;     // arc goes from top → left
                blockH += side;
                break;
        }

        arcs.push({
            x: pivotX,
            y: pivotY,
            r: r,
            startAngle: startAngle,
            endAngle: startAngle - Math.PI / 2,   // always sweep −90°
            color: `hsl(${(i / N) * 280 + 180}, 80%, 65%)`
        });

        dir++;
    }

    return arcs;
}

// Build arc sets for both versions
const buggyArcs = buildArcs(Array.from({ length: N }, (_, i) => fibBuggy(i)), SCALE);
const fixedArcs = buildArcs(fibSeq, SCALE);

/* ─────────────────────────────────────────────
   RENDER FUNCTION
───────────────────────────────────────────── */
function renderCanvas(canvasId, arcs, count, isBuggy) {
    const canvas = document.getElementById(canvasId);
    const ctx    = canvas.getContext('2d');
    const W = canvas.width, H = canvas.height;

    ctx.clearRect(0, 0, W, H);

    // Background
    ctx.fillStyle = '#0d0d18';
    ctx.fillRect(0, 0, W, H);

    // Grid
    ctx.strokeStyle = '#1a1a2a';
    ctx.lineWidth = 0.5;
    for (let x = 0; x < W; x += 20) {
        ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, H); ctx.stroke();
    }
    for (let y = 0; y < H; y += 20) {
        ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(W, y); ctx.stroke();
    }

    if (isBuggy) {
        // Draw the buggy arcs (all radius 0 → invisible)
        // Show a "ghost" of where they SHOULD be, plus error markers
        for (let i = 0; i < count; i++) {
            const a = arcs[i];

            // Ghost arc (where the correct arc would be) — very faint
            const ghostR = fibFixed(i) * SCALE;
            if (ghostR > 0) {
                ctx.beginPath();
                ctx.arc(a.x, a.y, ghostR, a.startAngle, a.endAngle, true);
                ctx.strokeStyle = '#ff6b6b18';
                ctx.lineWidth = ghostR > 2 ? 3 : 1;
                ctx.setLineDash([4, 6]);
                ctx.stroke();
                ctx.setLineDash([]);
            }

            // Error marker at pivot
            ctx.beginPath();
            ctx.arc(a.x, a.y, 5, 0, Math.PI * 2);
            ctx.fillStyle = '#ff6b6b88';
            ctx.fill();

            // Radius = 0 label
            if (i < 6) {
                ctx.fillStyle = '#ff6b6b';
                ctx.font = '10px Courier New';
                ctx.fillText(`fib(${i})=0`, a.x + 8, a.y - 8);
            }
        }

        // Big error message
        if (count > 0) {
            ctx.fillStyle = '#ff6b6b22';
            ctx.fillRect(0, 0, W, H);
            ctx.fillStyle = '#ff6b6b';
            ctx.font = 'bold 16px Courier New';
            ctx.textAlign = 'center';
            ctx.fillText('All radii = 0', W / 2, H / 2 - 12);
            ctx.font = '12px Courier New';
            ctx.fillStyle = '#ff6b6b88';
            ctx.fillText('fib(1) returns 0 → sequence broken', W / 2, H / 2 + 12);
            ctx.fillText('Ghost arcs show correct positions', W / 2, H / 2 + 30);
            ctx.textAlign = 'left';
        }

    } else {
        // Draw the FIXED arcs properly
        for (let i = 0; i < count; i++) {
            const a = arcs[i];
            if (a.r < 1) continue;

            // Arc stroke
            ctx.beginPath();
            ctx.arc(a.x, a.y, a.r, a.startAngle, a.endAngle, true);
            ctx.strokeStyle = a.color;
            ctx.lineWidth = 2.5;
            ctx.shadowColor = a.color;
            ctx.shadowBlur = 10;
            ctx.stroke();
            ctx.shadowBlur = 0;

            // Pivot dot
            ctx.beginPath();
            ctx.arc(a.x, a.y, 3, 0, Math.PI * 2);
            ctx.fillStyle = a.color + 'aa';
            ctx.fill();

            // Label
            if (a.r > 20) {
                ctx.fillStyle = a.color + 'cc';
                ctx.font = '10px Courier New';
                ctx.fillText(`fib(${i})=${fibFixed(i)}`, a.x + 5, a.y - 5);
            }
        }
    }

    // Arc count badge
    ctx.fillStyle = '#ffffff11';
    ctx.beginPath();
    ctx.roundRect(8, 8, 110, 26, 6);
    ctx.fill();
    ctx.fillStyle = isBuggy ? '#ff6b6b' : '#6bff8e';
    ctx.font = '11px Courier New';
    ctx.fillText(`arcs: ${count} / ${N}`, 16, 25);
}

/* ─────────────────────────────────────────────
   ANIMATION CONTROLLER
───────────────────────────────────────────── */
let currentStep = 0;
let animId = null;
let animating = false;

function updateStep(step) {
    currentStep = Math.max(0, Math.min(step, N));
    document.getElementById('stepCounter').textContent =
        `Arcs drawn: ${currentStep} / ${N}`;
    renderCanvas('buggyCanvas', buggyArcs, currentStep, true);
    renderCanvas('fixedCanvas', fixedArcs, currentStep, false);
}

function animate() {
    if (currentStep >= N) {
        animating = false;
        document.getElementById('btnAnimate').textContent = '▶ Animate Both';
        return;
    }
    currentStep++;
    updateStep(currentStep);
    animId = setTimeout(animate, 420);
}

document.getElementById('btnAnimate').addEventListener('click', () => {
    if (animating) {
        clearTimeout(animId);
        animating = false;
        document.getElementById('btnAnimate').textContent = '▶ Animate Both';
    } else {
        if (currentStep >= N) currentStep = 0;
        animating = true;
        document.getElementById('btnAnimate').textContent = '⏸ Pause';
        animate();
    }
});

document.getElementById('btnStep').addEventListener('click', () => {
    clearTimeout(animId);
    animating = false;
    document.getElementById('btnAnimate').textContent = '▶ Animate Both';
    updateStep(currentStep + 1);
});

document.getElementById('btnReset').addEventListener('click', () => {
    clearTimeout(animId);
    animating = false;
    document.getElementById('btnAnimate').textContent = '▶ Animate Both';
    updateStep(0);
});

// Initial render
updateStep(0);
</script>
</body>
</html>
