<script>
"use strict";

/* ─────────────────────────────────────────────────────────────────────
   FIBONACCI SEQUENCE BUILDERS
   The ONLY difference between buggy and fixed is fib[0] and fib[1].
───────────────────────────────────────────────────────────────────── */

function buildFibBuggy(n) {
    const fib = [];
    fib[0] = 0;   // ← BUG: zero base case
    fib[1] = 0;   // ← BUG: zero base case
    for (let i = 2; i < n; i++) {
        fib[i] = fib[i - 1] + fib[i - 2];   // 0+0=0 forever
    }
    return fib;
}

function buildFibFixed(n) {
    const fib = [];
    fib[0] = 1;   // ✓ FIXED
    fib[1] = 1;   // ✓ FIXED
    for (let i = 2; i < n; i++) {
        fib[i] = fib[i - 1] + fib[i - 2];   // 1,1,2,3,5,8,13,21…
    }
    return fib;
}

/* ─────────────────────────────────────────────────────────────────────
   SPIRAL RENDERER
   Draws n quarter-circle arcs.  Each arc:
     • radius  = fib[i] * scale
     • centre  = corner of the current Fibonacci square
     • angle   = rotates 90° per step (right→down→left→up)

   direction cycling:  0=right  1=down  2=left  3=up
   The pivot (arc centre) shifts by fib[i-1]*scale in the
   direction perpendicular to the current sweep.
───────────────────────────────────────────────────────────────────── */

function drawSpiral(ctx, fibs, steps, scale, palette) {
    const W = ctx.canvas.width;
    const H = ctx.canvas.height;

    ctx.clearRect(0, 0, W, H);

    // Draw grid background
    ctx.strokeStyle = "rgba(255,255,255,0.04)";
    ctx.lineWidth = 0.5;
    for (let x = 0; x <= W; x += 20) {
        ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, H); ctx.stroke();
    }
    for (let y = 0; y <= H; y += 20) {
        ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(W, y); ctx.stroke();
    }

    if (steps === 0) return;

    // Starting position — offset so spiral sits nicely in canvas
    // We start with the first square at the centre-left area
    let cx = W * 0.42;
    let cy = H * 0.52;

    // Direction state: 0=right,1=down,2=left,3=up
    // Arc sweep angles for each direction (quarter circle)
    // dir 0 (right): arc sweeps from 180° to 270° (top-left corner pivot)
    // dir 1 (down):  arc sweeps from 270° to 360°
    // dir 2 (left):  arc sweeps from   0° to  90°
    // dir 3 (up):    arc sweeps from  90° to 180°
    const arcAngles = [
        [Math.PI,       Math.PI * 1.5],   // right
        [Math.PI * 1.5, Math.PI * 2],     // down
        [0,             Math.PI * 0.5],   // left
        [Math.PI * 0.5, Math.PI],         // up
    ];

    // After drawing arc i (radius r_i), the pivot moves to the next corner.
    // Offset applied to cx,cy before drawing arc i+1:
    //   dir 0→1: cx += r_i,  cy += 0       (move right by r_i)
    //   dir 1→2: cx += 0,    cy += r_i      (move down  by r_i)
    //   dir 2→3: cx -= r_i,  cy += 0        (move left  by r_i)
    //   dir 3→0: cx += 0,    cy -= r_i      (move up    by r_i)
    // WAIT — actually we shift by the CURRENT radius each time.
    // Let's track carefully step by step.

    for (let i = 0; i < steps && i < fibs.length; i++) {
        const r   = fibs[i] * scale;
        const dir = i % 4;
        const [startAngle, endAngle] = arcAngles[dir];

        // Hue cycles through the palette colours
        const color = palette[i % palette.length];

        // Draw the Fibonacci square outline (subtle)
        ctx.strokeStyle = color + "33";
        ctx.lineWidth   = 0.8;
        let sx, sy;
        switch (dir) {
            case 0: sx = cx - r; sy = cy - r; break;
            case 1: sx = cx;     sy = cy - r; break;
            case 2: sx = cx;     sy = cy;     break;
            case 3: sx = cx - r; sy = cy;     break;
        }
        ctx.strokeRect(sx, sy, r, r);

        // Draw the arc
        ctx.beginPath();
        ctx.arc(cx, cy, r, startAngle, endAngle);
        ctx.strokeStyle = color;
        ctx.lineWidth   = 2.5;
        ctx.stroke();

        // Draw a dot at the pivot
        ctx.beginPath();
        ctx.arc(cx, cy, 3, 0, Math.PI * 2);
        ctx.fillStyle = color;
        ctx.fill();

        // Advance pivot to the corner of the NEXT square
        switch (dir) {
            case 0: cx += r;  break;   // move right
            case 1: cy += r;  break;   // move down
            case 2: cx -= r;  break;   // move left
            case 3: cy -= r;  break;   // move up
        }
    }
}

/* ─────────────────────────────────────────────────────────────────────
   SEQUENCE CHIP DISPLAY
───────────────────────────────────────────────────────────────────── */

function renderSeqChips(containerId, fibs, highlightClass) {
    const el = document.getElementById(containerId);
    el.innerHTML = "";
    fibs.forEach((v, i) => {
        const chip = document.createElement("span");
        chip.className = "seq-chip" + (i < 2 ? ` ${highlightClass}` : "");
        chip.textContent = `fib[${i}]=${v}`;
        el.appendChild(chip);
    });
}

/* ─────────────────────────────────────────────────────────────────────
