<script>
/* ═══════════════════════════════════════════════════════════════
   FIBONACCI HELPERS
═══════════════════════════════════════════════════════════════ */

/** Buggy: second seed is 0 instead of 1 */
function fibSequenceBuggy(count) {
  const seq = [];
  let a = 0, b = 0; // ← THE BUG
  for (let i = 0; i < count; i++) {
    seq.push(a);
    [a, b] = [b, a + b];
  }
  return seq;
}

/** Correct: seeds are 0, 1 */
function fibSequenceFixed(count) {
  const seq = [];
  let a = 0, b = 1;
  for (let i = 0; i < count; i++) {
    seq.push(a);
    [a, b] = [b, a + b];
  }
  return seq;
}

/* ═══════════════════════════════════════════════════════════════
   SPIRAL RENDERER
   Each step draws one quarter-circle arc whose radius = fib[i].
   The pivot corner rotates 90° counter-clockwise each step.
═══════════════════════════════════════════════════════════════ */

/**
 * @param {CanvasRenderingContext2D} ctx
 * @param {number[]} fibs   - array of fibonacci values
 * @param {number}   scale  - pixels per unit
 */
function drawSpiral(ctx, fibs, scale) {
  const W = ctx.canvas.width;
  const H = ctx.canvas.height;

  ctx.clearRect(0, 0, W, H);

  // ── background grid ──────────────────────────────────────────
  ctx.save();
  ctx.strokeStyle = '#1e2540';
  ctx.lineWidth = 0.5;
  const step = scale;
  for (let x = 0; x < W; x += step) {
    ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, H); ctx.stroke();
  }
  for (let y = 0; y < H; y += step) {
    ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(W, y); ctx.stroke();
  }
  ctx.restore();

  // ── colour palette for arcs ───────────────────────────────────
  const palette = [
    '#f87171','#fb923c','#fbbf24','#a3e635',
    '#34d399','#22d3ee','#60a5fa','#a78bfa',
    '#f472b6','#e879f9','#38bdf8','#4ade80',
  ];

  // ── pivot logic ───────────────────────────────────────────────
  // We track the "origin" of the current square.
  // Rotation order: right→up→left→down (CCW quarters).
  //
  // Each arc sweeps a quarter circle.
  // The centre of the arc is the corner of the square opposite
  // to the direction of travel.
  //
  // Angle offsets per rotation step (start, end):
  //   step 0 (→): arc from 180° to 270°  (bottom-left corner)
  //   step 1 (↑): arc from 270° to 360°  (bottom-right corner)
  //   step 2 (←): arc from   0° to  90°  (top-right corner)
  //   step 3 (↓): arc from  90° to 180°  (top-left corner)

  const TAU = Math.PI * 2;
  const HALF_PI = Math.PI / 2;

  // Arc definitions per rotation phase [startAngle, endAngle, cx offset, cy offset]
  // offsets are relative to the square's top-left corner, in units of `r`
  const arcDefs = [
    // phase 0: moving right  → arc centre at bottom-left of square
    { sa: Math.PI,       ea: Math.PI * 1.5, dcx: 0, dcy: 1 },
    // phase 1: moving up    → arc centre at bottom-right
    { sa: Math.PI * 1.5, ea: TAU,           dcx: 1, dcy: 1 },
    // phase 2: moving left  → arc centre at top-right
    { sa: 0,             ea: HALF_PI,       dcx: 1, dcy: 0 },
    // phase 3: moving down  → arc centre at top-left
    { sa: HALF_PI,       ea: Math.PI,       dcx: 0, dcy: 0 },
  ];

  // Starting position: centre the spiral roughly in the canvas
  // We place the first square's top-left here.
  let ox = W / 2 - scale * 1.5;
  let oy = H / 2 - scale * 1.5;

  // Displacement of top-left corner after each arc, per phase
  // After drawing a square of size r at (ox,oy):
  //   phase 0 (→): next square goes right  → ox += r, oy stays
  //   phase 1 (↑): next square goes up     → oy -= r
  //   phase 2 (←): next square goes left   → ox -= nextR (handled after)
  //   phase 3 (↓): next square goes down   → oy += r
  // Actually it's cleaner to compute the new origin after each step.

  const N = fibs.length;

  for (let i = 0; i < N; i++) {
    const r = fibs[i] * scale;
    if (r <= 0) continue; // skip zero-radius arcs (buggy sequence produces these)

    const phase = i % 4;
    const def   = arcDefs[phase];
    const color = palette[i % palette.length];

    // Centre of the arc circle
    const cx = ox + def.dcx * r;
    const cy = oy + def.dcy * r;

    // ── draw filled square ──────────────────────────────────────
    ctx.save();
    ctx.fillStyle = color + '18'; // very transparent fill
    ctx.strokeStyle = color + '55';
    ctx.lineWidth = 0.8;
    ctx.fillRect(ox, oy, r, r);
    ctx.strokeRect(ox, oy, r, r);
    ctx.restore();

    // ── draw arc ────────────────────────────────────────────────
    ctx.save();
    ctx.beginPath();
    ctx.arc(cx, cy, r, def.sa, def.ea, false);
    ctx.strokeStyle = color;
    ctx.lineWidth = 2.5;
    ctx.shadowColor = color;
    ctx.shadowBlur = 8;
    ctx.stroke();
    ctx.restore();

    // ── label the square ────────────────────────────────────────
    if (r >= 14) {
      ctx.save();
      ctx.fillStyle = color + 'cc';
      ctx.font = `bold ${Math.min(r * 0.28, 13)}px monospace`;
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(fibs[i], ox + r / 2, oy + r / 2);
      ctx.restore();
    }

    // ── advance origin ───────────────────────────────────────────
    const nextR = (i + 1 < N) ? fibs[i + 1] * scale : 0;
    switch (phase) {
      case 0: ox += r;          break; // moved right: next square above current
      case 1: oy -= nextR;      break; // moved up:   next square to the left
      case 2: ox -= nextR; oy += r; break; // moved left: next square below
      case 3: ox += r;   oy += r; break; // moved down: next square to the right
    }
  }
}

/* ═══════════════════════════════════════════════════════════════
   INITIALISE BOTH CANVASES
═══════════════════════════════════════════════════════════════ */

