  [Math.PI * 1.5, Math.PI * 2  ], // Q1
  [0,             Math.PI * 0.5], // Q2
  [Math.PI * 0.5, Math.PI      ], // Q3
];

function generateFib(n, seed1, seed2) {
  const seq = [seed1, seed2];
  for (let i = 2; i < n; i++) seq.push(seq[i - 1] + seq[i - 2]);
  return seq;
