  ctx.strokeStyle = '#1f2540';
  ctx.lineWidth   = 1;
  const GRID = 40;
  for (let x = 0; x <= W; x += GRID) {
    ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, H); ctx.stroke();
  }
  for (let y = 0; y <= H; y += GRID) {
    ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(W, y); ctx.stroke();
  }

  const N   = 10;
  const seq = generateFib(N, seed1, seed2);

  // Scale so the total width fits comfortably
  const totalSpan = seq[N - 1] + seq[N - 2];
  const scale     = totalSpan > 0 ? (W * 0.85) / totalSpan : 1;

  // Start pivot near centre-left so the spiral expands rightward
  let px = W * 0.38;
  let py = H * 0.55;

  const palette = [
    '#f43f5e','#fb923c','#facc15',
    '#4ade80','#34d399','#22d3ee',
    '#60a5fa','#a78bfa','#e879f9','#f472b6',
  ];

  // ── Draw squares first (background layer) ──
  let spx = px, spy = py;
  for (let i = 1; i < N; i++) {
    const size = seq[i] * scale;
    const dir  = DIRECTIONS[(i - 1) % 4];
    const quad = (i - 1) % 4;

    // Determine square top-left corner based on quadrant
    let sx = spx, sy = spy;
    if (quad === 0) { sx = spx;        sy = spy - size; }
    if (quad === 1) { sx = spx - size; sy = spy - size; }
    if (quad === 2) { sx = spx - size; sy = spy;        }
    if (quad === 3) { sx = spx;        sy = spy;        }

    ctx.fillStyle   = palette[i % palette.length] + '18';
    ctx.strokeStyle = palette[i % palette.length] + '55';
    ctx.lineWidth   = 1;
    ctx.fillRect(sx, sy, size, size);
    ctx.strokeRect(sx, sy, size, size);

    // Label the square with its Fibonacci number
    if (size > 18) {
      ctx.fillStyle = palette[i % palette.length] + 'aa';
      ctx.font      = `bold ${Math.min(size * 0.28, 18)}px monospace`;
      ctx.textAlign = 'center';
      ctx.fillText(seq[i], sx + size / 2, sy + size / 2 + 5);
