  ctx.lineWidth   = 3;
  ctx.shadowBlur  = 12;

  for (let i = 1; i < N; i++) {
    const size   = seq[i] * scale;
    const quad   = (i - 1) % 4;
    const [startA, endA] = ARC_ANGLES[quad];

    ctx.strokeStyle = palette[i % palette.length];
    ctx.shadowColor = palette[i % palette.length];
    ctx.beginPath();
    ctx.arc(px, py, size, startA, endA);
    ctx.stroke();

    const dir = DIRECTIONS[quad];
    px += dir[0] * size;
    py += dir[1] * size;
