    ctx.fill();
    ctx.shadowBlur = 0;

    ctx.fillStyle = '#fca5a5';
    ctx.font      = '12px monospace';
    ctx.textAlign = 'left';
    ctx.fillText('← all arcs collapsed here', px + 14, py + 4);
