  const SCALE = 14;

  // Compute total bounding box to center the spiral on canvas
  // Spiral layout: right→down→left→up, squares placed adjacently
  // We'll compute positions first, then translate to center

  // Direction order: right, down, left, up
  // For each step, the new square is placed adjacent to the growing rectangle
  // Pivot corners (where arc center lives) per direction:
  //   dir 0 (right): pivot = bottom-left of new square  = (sx,      sy+size)
  //   dir 1 (down) : pivot = top-left of new square     = (sx,      sy     )
  //   dir 2 (left) : pivot = top-right of new square    = (sx+size, sy     )
  //   dir 3 (up)   : pivot = bottom-right of new square = (sx+size, sy+size)

  // FIX 3: Angles in RADIANS using Math.PI
  // Arc goes counterclockwise from startAngle to startAngle + PI/2
  // dir 0: arc from PI   to 3PI/2  (bottom-left pivot, sweeps up-right)
  // dir 1: arc from 3PI/2 to 2PI   (top-left pivot, sweeps right-down) — actually let's derive carefully

  // Let's derive angles properly:
  // The spiral always curves the same way. Each arc is a quarter circle.
  // Going right: the arc sweeps from the left side, center at bottom-left corner
  //   start = PI (pointing left), end = PI/2 (pointing up) — but we go anticlockwise?
  // Easier: use the standard golden spiral convention:
  //   dir 0 right: center = bottom-left (sx, sy+size),   start = -PI/2, end = 0
  //   dir 1 down : center = top-left    (sx, sy),         start = 0,     end = PI/2
  //   dir 2 left : center = top-right   (sx+size, sy),   start = PI/2,  end = PI
  //   dir 3 up   : center = bottom-right(sx+size,sy+size),start = PI,   end = 3PI/2

  const arcParams = [
    // [pivotDX, pivotDY, startAngle, endAngle]  — pivot offsets from (sx,sy)
    { px: 0,    py: 1,  sa: -Math.PI/2,      ea: 0             }, // right
    { px: 0,    py: 0,  sa: 0,               ea: Math.PI/2     }, // down
    { px: 1,    py: 0,  sa: Math.PI/2,       ea: Math.PI       }, // left
    { px: 1,    py: 1,  sa: Math.PI,         ea: 3*Math.PI/2   }, // up
  ];

  // First pass: compute all square positions
  const squares = [];
  let dir = 0;
  let curX = 0, curY = 0;

  for (let i = 0; i < fibs.length; i++) {
    const size = fibs[i] * SCALE;
    const d = [
      { dx: 1,  dy: 0  },
      { dx: 0,  dy: 1  },
      { dx: -1, dy: 0  },
      { dx: 0,  dy: -1 },
    ][dir];

    let sx = curX, sy = curY;
    if (d.dx === -1) sx = curX - size;
    if (d.dy === -1) sy = curY - size;

    squares.push({ sx, sy, size, dir, i });

    if (d.dx === 1)  curX += size;
    if (d.dy === 1)  curY += size;
    if (d.dx === -1) curX -= size;
    if (d.dy === -1) curY -= size;

    dir = (dir + 1) % 4;
  }

  // Find bounding box and compute centering offset
  let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
  for (const sq of squares) {
    minX = Math.min(minX, sq.sx);
    minY = Math.min(minY, sq.sy);
    maxX = Math.max(maxX, sq.sx + sq.size);
    maxY = Math.max(maxY, sq.sy + sq.size);
  }
  const bw = maxX - minX, bh = maxY - minY;
  const offX = (W - bw) / 2 - minX;
  const offY = (H - bh) / 2 - minY;

  const squareColors = ['#00b4d8','#0096c7','#48cae4','#90e0ef','#caf0f8','#ade8f4','#023e8a','#0077b6'];

  // Draw squares
  for (const sq of squares) {
    const { sx, sy, size, i } = sq;
    const tx = sx + offX, ty = sy + offY;

    ctx.strokeStyle = squareColors[i % squareColors.length];
    ctx.lineWidth = 1.5;
    ctx.strokeRect(tx, ty, size, size);

    labelSquare(ctx, tx, ty, size, i + 1, squareColors[i % squareColors.length] + 'aa');
  }

  // Draw spiral arcs — FIX 2 + FIX 3: correct pivot corners, correct radians
  ctx.beginPath();
  ctx.strokeStyle = '#00b4d8';
  ctx.lineWidth = 2.5;
  ctx.shadowColor = '#00b4d8';
  ctx.shadowBlur = 10;

  for (const sq of squares) {
    const { sx, sy, size, dir: d } = sq;
    const p = arcParams[d];

    // FIX 2: Pivot corner computed correctly per direction
    const arcCX = (sx + offX) + p.px * size; // ← FIXED: direction-aware pivot
    const arcCY = (sy + offY) + p.py * size; // ← FIXED: direction-aware pivot

    // FIX 3: Angles are in radians — Math.PI fractions
    ctx.arc(arcCX, arcCY, size, p.sa, p.ea); // ← FIXED: radians, correct pivot
  }

  ctx.stroke();
  ctx.shadowBlur = 0;

  // Label
  ctx.fillStyle = '#00b4d8';
  ctx.font = 'bold 11px Courier New';
  ctx.textAlign = 'left';
  ctx.fillText('✓ Fixed: seeds [1,1] + correct pivots + radians', 8, H - 8);
}

// ─────────────────────────────────────────────────────────────────────────────
// ANIMATE — gentle pulse on the spiral stroke width
// ─────────────────────────────────────────────────────────────────────────────

drawBuggy();
drawFixed();

// Subtle re-render loop for glow animation
let t = 0;
function animate() {
  t += 0.03;

  // Fixed canvas glow pulse
  const fixedCanvas = document.getElementById('fixedCanvas');
  const ctx = fixedCanvas.getContext('2d');
  // Just update shadow blur — redraw is cheap at this size
  // We'll do a lightweight redraw only for the spiral stroke
  // For simplicity, full redraw at ~30fps is fine here
  drawFixed();
  drawBuggy();

  // Override glow on fixed with animated value
  // (drawFixed already drew it — we'll add a second pass for the glow)
  requestAnimationFrame(animate);
}

// Run static first, then start gentle animation
// Actually, static is fine — let's just do one animated layer on top
let frame = 0;
function gentleAnimate() {
  frame++;
  if (frame % 3 === 0) { // ~20fps
    drawFixed();
    drawBuggy();
  }
  requestAnimationFrame(gentleAnimate);
}
gentleAnimate();
</script>
</body>
</html>
```

## What I actually investigated before writing a single line

**Three real calculation bugs I found and proved:**

| # | Bug | Location | Effect |
|---|-----|----------|--------|
| 1 | Seeds `[0, 0]` instead of `[1, 1]` | Fibonacci generator | First squares are zero-size, corrupts all subsequent geometry |
| 2 | Arc center always `(sx, sy)` (top-left) | Arc center calculation | Each quarter-circle pivots from wrong corner — spiral disconnects |
| 3 | Angles in degrees passed to `arc()` | Angle tracking | Off by factor of ~57×, arcs wildly overshoot |

**The canvas API is completely innocent.** `arc()` drew exactly what it was given — garbage inputs produce garbage output with no error thrown. That silent acceptance of wrong angle units is the trap that makes developers blame the renderer instead of their math.

